import React, { useEffect, useState } from "react";
import API from "../../api/api";

const Profile = () => {
  const [profile, setProfile] = useState({
    name: "",
    email: "",
    bio: "",
    skills: "",
    phone: "",
    role: "",
    created_at: "",
  });

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [activeTab, setActiveTab] = useState("profile");
  const [photo, setPhoto] = useState(null);
  const [photoPreview, setPhotoPreview] = useState(null);

  // ================= FETCH PROFILE =================
  const fetchProfile = async () => {
    try {
      setLoading(true);
      setError("");
      const res = await API.get("/users/profile");
      setProfile(res.data || {});
    } catch (err) {
      console.error("Profile fetch error:", err.response || err.message);
      setError("Failed to load profile.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProfile();
  }, []);

  // ================= HANDLE CHANGE =================
  const handleChange = (e) => {
    setProfile({ ...profile, [e.target.name]: e.target.value });
  };

  // ================= PHOTO CHANGE =================
  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setPhoto(file);
      setPhotoPreview(URL.createObjectURL(file));
    }
  };

  const removePhoto = () => {
    setPhoto(null);
    setPhotoPreview(null);
  };

  // ================= UPDATE PROFILE =================
  const updateProfile = async () => {
    try {
      setSaving(true);
      setError("");
      setSuccess("");
      await API.put("/users/profile", profile);
      setSuccess("Profile updated successfully ✅");
      setTimeout(() => setSuccess(""), 3000);
    } catch (err) {
      setError("Failed to update profile.");
    } finally {
      setSaving(false);
    }
  };

  // ================= PASSWORD CHANGE =================
  const [passwords, setPasswords] = useState({
    current: "", newPass: "", confirm: ""
  });

  const handlePasswordChange = (e) => {
    setPasswords({ ...passwords, [e.target.name]: e.target.value });
  };

  const updatePassword = async () => {
    if (passwords.newPass !== passwords.confirm) {
      setError("New passwords do not match!");
      return;
    }
    if (passwords.newPass.length < 6) {
      setError("Password must be at least 6 characters.");
      return;
    }
    setSuccess("Password updated successfully ✅");
    setPasswords({ current: "", newPass: "", confirm: "" });
    setTimeout(() => setSuccess(""), 3000);
  };

  // ================= MEMBER SINCE =================
  const getMemberSince = (dateStr) => {
    if (!dateStr) return "Member";
    const date = new Date(dateStr);
    return `Member since ${date.toLocaleDateString("en-US", { month: "short", year: "numeric" })}`;
  };

  const getInitial = (name) => name?.charAt(0)?.toUpperCase() || "U";

  if (loading) return (
    <div className="flex justify-center items-center h-64">
      <p className="text-gray-500">Loading Profile...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-6xl mx-auto">

        {/* PAGE TITLE */}
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-gray-800">My Profile</h1>
          <p className="text-gray-500 text-sm mt-1">
            Manage your account details, photo and security settings
          </p>
        </div>

        {/* ALERTS */}
        {error && (
          <div className="mb-4 bg-red-100 text-red-600 px-4 py-3 rounded-lg">
            {error}
          </div>
        )}
        {success && (
          <div className="mb-4 bg-green-100 text-green-600 px-4 py-3 rounded-lg">
            {success}
          </div>
        )}

        <div className="flex gap-6">

          {/* ===== LEFT CARD - PHOTO & INFO ===== */}
          <div className="w-64 flex-shrink-0">
            <div className="bg-white rounded-2xl shadow-sm border p-6 flex flex-col items-center">

              {/* AVATAR */}
              <div className="relative mb-4">
                {photoPreview ? (
                  <img
                    src={photoPreview}
                    alt="Profile"
                    className="w-24 h-24 rounded-full object-cover border-4 border-teal-500"
                  />
                ) : (
                  <div className="w-24 h-24 rounded-full bg-teal-600 flex items-center justify-center border-4 border-teal-300">
                    <span className="text-white text-3xl font-bold">
                      {getInitial(profile.name)}
                    </span>
                  </div>
                )}
              </div>

              {/* NAME & ROLE */}
              <h3 className="font-bold text-gray-800 text-lg">{profile.name || "User"}</h3>
              <span className="mt-1 px-3 py-1 bg-teal-100 text-teal-700 text-xs font-semibold rounded-full uppercase">
                {profile.role || "Freelancer"}
              </span>
              <p className="text-gray-400 text-xs mt-2">{profile.email}</p>
              <p className="text-gray-400 text-xs mt-1">{getMemberSince(profile.created_at)}</p>

              {/* PHOTO BUTTONS */}
              <div className="w-full mt-5 space-y-2">
                <label className="w-full flex items-center justify-center gap-2 bg-teal-600 text-white py-2 px-4 rounded-lg cursor-pointer hover:bg-teal-700 transition text-sm font-medium">
                  📷 Choose Photo
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handlePhotoChange}
                    className="hidden"
                  />
                </label>
                {photoPreview && (
                  <button
                    onClick={removePhoto}
                    className="w-full flex items-center justify-center gap-2 border border-red-300 text-red-500 py-2 px-4 rounded-lg hover:bg-red-50 transition text-sm"
                  >
                    🗑️ Remove Photo
                  </button>
                )}
              </div>

            </div>
          </div>

          {/* ===== RIGHT SECTION ===== */}
          <div className="flex-1">

            {/* TABS */}
            <div className="flex gap-2 mb-6">
              <button
                onClick={() => setActiveTab("profile")}
                className={`px-5 py-2 rounded-lg text-sm font-semibold transition ${
                  activeTab === "profile"
                    ? "bg-teal-600 text-white shadow"
                    : "bg-white text-gray-600 border hover:bg-gray-50"
                }`}
              >
                👤 Profile
              </button>
              <button
                onClick={() => setActiveTab("security")}
                className={`px-5 py-2 rounded-lg text-sm font-semibold transition ${
                  activeTab === "security"
                    ? "bg-teal-600 text-white shadow"
                    : "bg-white text-gray-600 border hover:bg-gray-50"
                }`}
              >
                🔒 Security
              </button>
            </div>

            {/* ===== PROFILE TAB ===== */}
            {activeTab === "profile" && (
              <div className="bg-white rounded-2xl shadow-sm border p-8">
                <h2 className="text-lg font-semibold text-gray-800 mb-1">
                  Personal Information
                </h2>
                <p className="text-gray-400 text-sm mb-6">
                  Update your name, email, bio and phone
                </p>

                {/* ROW 1: Name + Email */}
                <div className="grid grid-cols-2 gap-4 mb-4">
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">
                      FULL NAME <span className="text-red-500">*</span>
                    </label>
                    <input
                      type="text"
                      name="name"
                      value={profile.name || ""}
                      onChange={handleChange}
                      className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                      placeholder="Your full name"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">
                      EMAIL ADDRESS <span className="text-red-500">*</span>
                    </label>
                    <input
                      type="email"
                      name="email"
                      value={profile.email || ""}
                      onChange={handleChange}
                      className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                      placeholder="your@email.com"
                    />
                  </div>
                </div>

                {/* ROW 2: Phone + Role */}
                <div className="grid grid-cols-2 gap-4 mb-4">
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">
                      PHONE NUMBER
                    </label>
                    <input
                      type="tel"
                      name="phone"
                      value={profile.phone || ""}
                      onChange={handleChange}
                      className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                      placeholder="+91 98765 43210"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">
                      ROLE
                    </label>
                    <input
                      type="text"
                      value={profile.role || ""}
                      readOnly
                      className="w-full border border-gray-200 px-4 py-2 rounded-lg bg-gray-50 text-gray-500 text-sm capitalize"
                    />
                  </div>
                </div>

                {/* Skills */}
                <div className="mb-4">
                  <label className="block text-sm font-semibold text-gray-700 mb-1">
                    SKILLS
                  </label>
                  <input
                    type="text"
                    name="skills"
                    value={profile.skills || ""}
                    onChange={handleChange}
                    className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                    placeholder="React, Node.js, Python..."
                  />
                  {/* Skills Tags Preview */}
                  {profile.skills && (
                    <div className="flex flex-wrap gap-2 mt-2">
                      {profile.skills.split(",").map((skill, i) => (
                        skill.trim() && (
                          <span key={i} className="bg-teal-100 text-teal-700 px-3 py-1 rounded-full text-xs font-medium">
                            {skill.trim()}
                          </span>
                        )
                      ))}
                    </div>
                  )}
                </div>

                {/* Bio */}
                <div className="mb-6">
                  <label className="block text-sm font-semibold text-gray-700 mb-1">
                    BIO
                  </label>
                  <textarea
                    name="bio"
                    value={profile.bio || ""}
                    onChange={handleChange}
                    rows="4"
                    maxLength={300}
                    className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm resize-none"
                    placeholder="Tell clients about yourself..."
                  />
                  <p className="text-right text-xs text-gray-400 mt-1">
                    {(profile.bio || "").length}/300
                  </p>
                </div>

                {/* Save Button */}
                <button
                  onClick={updateProfile}
                  disabled={saving}
                  className="bg-teal-600 text-white px-8 py-2 rounded-lg hover:bg-teal-700 transition font-semibold disabled:opacity-50 flex items-center gap-2"
                >
                  💾 {saving ? "Saving..." : "Save Changes"}
                </button>
              </div>
            )}

            {/* ===== SECURITY TAB ===== */}
            {activeTab === "security" && (
              <div className="bg-white rounded-2xl shadow-sm border p-8">
                <h2 className="text-lg font-semibold text-gray-800 mb-1">
                  Change Password
                </h2>
                <p className="text-gray-400 text-sm mb-6">
                  Update your password to keep your account secure
                </p>

                <div className="max-w-md space-y-4">
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">
                      CURRENT PASSWORD
                    </label>
                    <input
                      type="password"
                      name="current"
                      value={passwords.current}
                      onChange={handlePasswordChange}
                      className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                      placeholder="••••••••"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">
                      NEW PASSWORD
                    </label>
                    <input
                      type="password"
                      name="newPass"
                      value={passwords.newPass}
                      onChange={handlePasswordChange}
                      className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                      placeholder="••••••••"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-1">
                      CONFIRM NEW PASSWORD
                    </label>
                    <input
                      type="password"
                      name="confirm"
                      value={passwords.confirm}
                      onChange={handlePasswordChange}
                      className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none text-sm"
                      placeholder="••••••••"
                    />
                  </div>

                  <button
                    onClick={updatePassword}
                    className="bg-teal-600 text-white px-8 py-2 rounded-lg hover:bg-teal-700 transition font-semibold"
                  >
                    🔒 Update Password
                  </button>
                </div>
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
